    error_message = "Environment must be 'dev' or 'prd'."
  }
}

variable "location" {
  description = "Azure region for resource deployment"
  type        = string
  default     = "brazilsouth"
}

variable "resource_group_name" {
  description = "Name of the resource group for networking resources"
  type        = string
