variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
}

variable "location" {
  description = "Azure region for resource deployment"
  type        = string
}

variable "resource_group_name" {
  description = "Name of the resource group for security resources"
  type        = string
}

# --------------------------------------------------------------------------
# Key Vault Configuration (AC 1)
# --------------------------------------------------------------------------

variable "key_vault_sku" {
  description = "SKU for Azure Key Vault (standard or premium)"
  type        = string
  default     = "standard"
  validation {
    condition     = contains(["standard", "premium"], var.key_vault_sku)
    error_message = "Key Vault SKU must be 'standard' or 'premium'."
  }
}

variable "key_vault_soft_delete_retention_days" {
  description = "Number of days to retain soft-deleted Key Vault (7-90)"
  type        = number
  default     = 90
  validation {
    condition     = var.key_vault_soft_delete_retention_days >= 7 && var.key_vault_soft_delete_retention_days <= 90
    error_message = "Soft delete retention must be between 7 and 90 days."
  }
}

# --------------------------------------------------------------------------
# Namespace Identity Configuration (AC 2)
# --------------------------------------------------------------------------

variable "namespaces" {
  description = "List of namespace names that require managed identities and Key Vault access"
  type        = list(string)
  default     = ["logistica"]
}

# --------------------------------------------------------------------------
# AKS Integration (AC 2, 3)
# --------------------------------------------------------------------------

variable "aks_oidc_issuer_url" {
  description = "OIDC Issuer URL from AKS cluster for Workload Identity federation"
  type        = string
}

variable "aks_subnet_id" {
  description = "Resource ID of the AKS subnet to allow in Key Vault network ACLs"
  type        = string
  default     = ""
}

# --------------------------------------------------------------------------
# Audit Configuration (Story 3.3)
# --------------------------------------------------------------------------

variable "audit_log_retention_days" {
  description = "Number of days to retain Key Vault audit logs (minimum 90 per NFR3)"
  type        = number
  default     = 90
  validation {
    condition     = var.audit_log_retention_days >= 90
    error_message = "Audit log retention must be at least 90 days per NFR3."
  }
}

# --------------------------------------------------------------------------
# Common
# --------------------------------------------------------------------------

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

# --------------------------------------------------------------------------
# ArgoCD Module (Story 4.4)
# Deploys ArgoCD on AKS via Helm provider.
# Architecture Decision 4.1: ApplicationSets with Git generator per namespace
# --------------------------------------------------------------------------

terraform {
  required_providers {
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.35"
    }
  }
}

# --------------------------------------------------------------------------
# ArgoCD Helm Release (Task 2: AC 1)
# Helm chart: argo/argo-cd from argoproj.github.io/argo-helm
# --------------------------------------------------------------------------

resource "helm_release" "argocd" {
  name             = "argocd"
  repository       = "https://argoproj.github.io/argo-helm"
  chart            = "argo-cd"
  version          = var.argocd_chart_version
  namespace        = var.argocd_namespace
  create_namespace = true
  timeout          = var.argocd_helm_timeout
  wait             = true
  atomic           = true

  # --------------------------------------------------------------------------
  # Server Configuration
  # --------------------------------------------------------------------------

  # ArgoCD server service type — ClusterIP for internal access
  set {
    name  = "server.service.type"
    value = "ClusterIP"
  }

  # --------------------------------------------------------------------------
  # Application Controller — Self-Heal & Drift Detection (AC 4, NFR12)
  # timeout.reconciliation controls how often ArgoCD checks for drift.
  # NFR12 requires drift revert within 3 minutes (180s).
  # --------------------------------------------------------------------------

  set {
    name  = "configs.cm.timeout\\.reconciliation"
    value = "${var.reconciliation_timeout_seconds}s"
  }

  # Enable status badge for monitoring
  set {
    name  = "configs.cm.statusbadge\\.enabled"
    value = "true"
  }

  # --------------------------------------------------------------------------
  # ApplicationSet Controller — enabled by default in argo-cd chart
  # Required for Git generator auto-discovery (AC 2, 3, 6)
  # --------------------------------------------------------------------------

  set {
    name  = "applicationSet.enabled"
    value = "true"
  }

  # --------------------------------------------------------------------------
  # Resource tracking — use annotation-based tracking
  # --------------------------------------------------------------------------

  set {
    name  = "configs.cm.application\\.resourceTrackingMethod"
    value = "annotation"
  }

  # --------------------------------------------------------------------------
  # Environment label for resource identification
  # --------------------------------------------------------------------------

  set {
    name  = "global.additionalLabels.environment"
    value = var.environment
  }

  set {
    name  = "global.additionalLabels.app\\.kubernetes\\.io/part-of"
    value = "python-governance"
  }
}

