  description = "List of business area namespace names for OTel Instrumentation CRs"
  type        = list(string)
  default     = ["logistica"]
}

# --------------------------------------------------------------------------
# AKS Integration
# --------------------------------------------------------------------------

variable "aks_oidc_issuer_url" {
  description = "OIDC Issuer URL from AKS cluster for Workload Identity federation"
