# --------------------------------------------------------------------------

variable "robusta_chart_version" {
  description = "Robusta Helm chart version"
  type        = string
  default     = "0.10.31"
}

variable "robusta_helm_timeout" {
  description = "Timeout in seconds for the Robusta Helm release"
  type        = number
  default     = 900
  validation {
    condition     = var.robusta_helm_timeout >= 120 && var.robusta_helm_timeout <= 1800
    error_message = "Helm timeout must be between 120 and 1800 seconds."
  }
}

