}

variable "mimir_helm_timeout" {
  description = "Timeout in seconds for the Mimir Helm release"
  type        = number
  default     = 600
}

variable "mimir_retention_days" {
  description = "Mimir long-term metrics retention in days (architecture: 365)"
  type        = number
  default     = 365
  validation {
    condition     = var.mimir_retention_days >= 30
    error_message = "Mimir retention must be at least 30 days."
  }
}

# --------------------------------------------------------------------------
# Loki Configuration (AC: #3)
# --------------------------------------------------------------------------

variable "loki_chart_version" {
  description = "Grafana Loki Helm chart version"
  type        = string
  default     = "6.53.0"
}

variable "loki_helm_timeout" {
  description = "Timeout in seconds for the Loki Helm release"
  type        = number
  default     = 600
}

# --------------------------------------------------------------------------
# Tempo Configuration (AC: #4)
# --------------------------------------------------------------------------

variable "tempo_chart_version" {
  description = "Grafana Tempo distributed Helm chart version"
  type        = string
  default     = "1.48.1"
}

variable "tempo_helm_timeout" {
  description = "Timeout in seconds for the Tempo Helm release"
  type        = number
  default     = 600
}

# --------------------------------------------------------------------------
# OpenTelemetry Operator Configuration (AC: #7)
# --------------------------------------------------------------------------

variable "otel_operator_chart_version" {
  description = "OpenTelemetry Operator Helm chart version"
  type        = string
  default     = "0.78.0"
}

variable "otel_operator_helm_timeout" {
  description = "Timeout in seconds for the OTel Operator Helm release"
  type        = number
  default     = 300
}

# --------------------------------------------------------------------------
# Common
# --------------------------------------------------------------------------

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

