# --------------------------------------------------------------------------
# OpenTelemetry Operator + Python Instrumentation CRs (Task 8: AC #7)
# Architecture Decision 5.1: Zero-code auto-instrumentation via pod annotations
# Traces sent to Tempo distributor on OTLP/HTTP port 4318
# --------------------------------------------------------------------------

resource "helm_release" "otel_operator" {
  name       = "opentelemetry-operator"
  repository = "https://open-telemetry.github.io/opentelemetry-helm-charts"
  chart      = "opentelemetry-operator"
  version    = var.otel_operator_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.otel_operator_helm_timeout
  wait       = true

  set {
    name  = "manager.collectorImage.repository"
    value = "otel/opentelemetry-collector-contrib"
  }

  depends_on = [
    kubernetes_namespace.monitoring,
    helm_release.tempo,
  ]
}

# --------------------------------------------------------------------------
# Python Instrumentation CR per business namespace (Task 8.2, 8.3)
# Creates an Instrumentation resource in each namespace so pods annotated
# with instrumentation.opentelemetry.io/inject-python: "true" get
# auto-instrumented with traces sent to Tempo distributor.
# --------------------------------------------------------------------------

resource "kubernetes_manifest" "otel_instrumentation" {
  for_each = toset(var.namespaces)

  manifest = {
    apiVersion = "opentelemetry.io/v1alpha1"
    kind       = "Instrumentation"

    metadata = {
      name      = "python-instrumentation"
      namespace = each.value
    }

    spec = {
      exporter = {
        endpoint = "http://tempo-distributor.${var.monitoring_namespace}.svc.cluster.local:4318"
      }

      propagators = ["tracecontext", "baggage"]

      python = {
        image = "ghcr.io/open-telemetry/opentelemetry-operator/autoinstrumentation-python:latest"
        env = [
          {
            name  = "OTEL_TRACES_EXPORTER"
            value = "otlp"
          },
          {
            name  = "OTEL_EXPORTER_OTLP_PROTOCOL"
            value = "http/protobuf"
          },
          {
            name  = "OTEL_RESOURCE_ATTRIBUTES"
            value = "service.namespace=${each.value},deployment.environment=${var.environment}"
          }
        ]
      }
    }
  }

  depends_on = [helm_release.otel_operator]
}

