  description = "Status of the ArgoCD Helm release"
  value       = module.argocd.argocd_release_status
}

output "argocd_applicationset_name" {
  description = "Name of the ArgoCD ApplicationSet for CronJob auto-discovery"
  value       = module.argocd.applicationset_name
}

