# --------------------------------------------------------------------------
# Monitoring Module (Story 5.1)
# Deploys LGTM observability stack on AKS via Helm provider.
# Architecture: Robusta (Prometheus+Grafana) → Mimir, Loki, Tempo backends
# --------------------------------------------------------------------------

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.60"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.35"
    }
  }
}

# --------------------------------------------------------------------------
# Monitoring Namespace
# Created explicitly — not via the namespaces module (infrastructure ns)
# --------------------------------------------------------------------------

resource "kubernetes_namespace" "monitoring" {
  metadata {
    name = var.monitoring_namespace

    labels = {
      "app.kubernetes.io/part-of" = "python-governance"
      "environment"               = var.environment
      "purpose"                   = "observability"
    }
  }
}

# ==========================================================================
# Task 5: Grafana Mimir — Distributed (AC: #2)
# Long-term metrics storage backed by Azure Blob (mimir-blocks)
# Deployed BEFORE Robusta so Prometheus can remote-write on startup
# ==========================================================================

resource "helm_release" "mimir" {
  name       = "mimir"
  repository = "https://grafana.github.io/helm-charts"
  chart      = "mimir-distributed"
  version    = var.mimir_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.mimir_helm_timeout
  wait       = true

  # --------------------------------------------------------------------------
  # Azure Blob Storage backend via Workload Identity
  # --------------------------------------------------------------------------

  # Common storage backend config
  values = [yamlencode({
    # Service account for Workload Identity
    serviceAccount = {
      annotations = {
        "azure.workload.identity/client-id" = azurerm_user_assigned_identity.lgtm.client_id
      }
      labels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Azure Blob Storage for blocks
    mimir = {
      structuredConfig = {
        common = {
          storage = {
            backend = "azure"
            azure = {
              account_name   = azurerm_storage_account.lgtm.name
              container_name = azurerm_storage_container.mimir_blocks.name
            }
          }
        }

        # Retention — 365 days per architecture
        limits = {
          compactor_blocks_retention_period = "${var.mimir_retention_days}d"
        }
      }
    }

    # Disable Kafka/ingest-storage (not needed, enabled by default in v6.x)
    mimir_config_override = {
      ingest_storage = {
        enabled = false
      }
    }

    # Minimal resource footprint for pilot
    ingester = {
      replicas = 2
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    distributor = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    compactor = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    store_gateway = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    querier = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    query_frontend = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Disable components not needed for pilot
    ruler = {
      enabled = false
    }
    alertmanager = {
      enabled = false
    }

    # Disable nginx gateway — use direct service access
    nginx = {
      enabled = false
    }
    gateway = {
      enabledNonEnterprise = false
    }
  })]

  depends_on = [kubernetes_namespace.monitoring]
}

# ==========================================================================
# Task 6: Grafana Loki (AC: #3)
# Centralized log collection backed by Azure Blob (loki-chunks)
# --------------------------------------------------------------------------

resource "helm_release" "loki" {
  name       = "loki"
  repository = "https://grafana.github.io/helm-charts"
  chart      = "loki"
  version    = var.loki_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.loki_helm_timeout
  wait       = true

  values = [yamlencode({
    # Deploy mode — scalable for production readiness
    deploymentMode = "SimpleScalable"

    loki = {
      # Authentication disabled for internal cluster use
      auth_enabled = false

      # Azure Blob Storage backend
      storage = {
        type = "azure"
        azure = {
          accountName   = azurerm_storage_account.lgtm.name
          containerName = azurerm_storage_container.loki_chunks.name
          useFederatedToken = true
        }
      }

      # TSDB schema v13 for efficient indexing (NFR21: <5s log queries)
      schemaConfig = {
        configs = [{
          from         = "2024-01-01"
          store        = "tsdb"
          object_store = "azure"
          schema       = "v13"
          index = {
            prefix = "loki_index_"
            period = "24h"
          }
        }]
      }
    }

    # Service account for Workload Identity
    serviceAccount = {
      annotations = {
        "azure.workload.identity/client-id" = azurerm_user_assigned_identity.lgtm.client_id
      }
      labels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Minimal replicas for pilot
    read = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    write = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    backend = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Disable embedded gateway — direct service access
    gateway = {
      enabled = false
    }

    # Disable test pod
    test = {
      enabled = false
    }
  })]

  depends_on = [kubernetes_namespace.monitoring]
}

# ==========================================================================
# Task 7: Grafana Tempo — Distributed (AC: #4)
# Distributed tracing backed by Azure Blob (tempo-traces)
# --------------------------------------------------------------------------

resource "helm_release" "tempo" {
  name       = "tempo"
  repository = "https://grafana.github.io/helm-charts"
  chart      = "tempo-distributed"
  version    = var.tempo_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.tempo_helm_timeout
  wait       = true

  values = [yamlencode({
    # Service account for Workload Identity
    serviceAccount = {
      annotations = {
        "azure.workload.identity/client-id" = azurerm_user_assigned_identity.lgtm.client_id
      }
      labels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Azure Blob Storage backend
    storage = {
      trace = {
        backend = "azure"
        azure = {
          container_name = azurerm_storage_container.tempo_traces.name
          storage_account_name = azurerm_storage_account.lgtm.name
          use_federated_token  = true
        }
      }
    }

    # Distributor — accept OTLP/HTTP on port 4318 (AC: #4, #7)
    distributor = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
      receivers = {
        otlp = {
          protocols = {
            http = {
              endpoint = "0.0.0.0:4318"
            }
            grpc = {
              endpoint = "0.0.0.0:4317"
            }
          }
        }
      }
    }

    # Minimal replicas for pilot
    ingester = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    compactor = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    querier = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }
    queryFrontend = {
      replicas = 1
      podLabels = {
        "azure.workload.identity/use" = "true"
      }
    }

    # Disable components not needed
    metricsGenerator = {
      enabled = false
    }
  })]

  depends_on = [kubernetes_namespace.monitoring]
}

# ==========================================================================
# Task 4: Robusta with kube-prometheus-stack (AC: #1, #5, #6)
# SINGLE Grafana instance embedded in Robusta connects to Mimir, Loki, Tempo
# Prometheus remote-writes to Mimir for long-term storage
# Deployed AFTER Mimir/Loki/Tempo so data sources are available
# ==========================================================================

resource "helm_release" "robusta" {
  name       = "robusta"
  repository = "https://robusta-charts.storage.googleapis.com"
  chart      = "robusta"
  version    = var.robusta_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.robusta_helm_timeout
  wait       = true

  values = [yamlencode({
    # Disable Robusta runner for now — alert enrichment configured in Story 7.1
    runner = {
      enabled = false
    }

    # --------------------------------------------------------------------------
    # kube-prometheus-stack configuration (embedded Prometheus + Grafana)
    # --------------------------------------------------------------------------
    kube-prometheus-stack = {

      # Prometheus configuration
      prometheus = {
        prometheusSpec = {
          # Scrape interval <= 30s per NFR26
          scrapeInterval = var.prometheus_scrape_interval

          # Remote write to Mimir for long-term storage (AC: #2)
          remoteWrite = [{
            url = "http://mimir-distributor.${var.monitoring_namespace}.svc.cluster.local:8080/api/v1/push"
          }]

          # Retention — short local retention since Mimir stores long-term
          retention = "2d"

          # Resource limits for pilot
          resources = {
            requests = {
              cpu    = "500m"
              memory = "1Gi"
            }
            limits = {
              cpu    = "2"
              memory = "4Gi"
            }
          }
        }
      }

      # Grafana — SINGLE instance connecting to Mimir, Loki, Tempo (AC: #5)
      grafana = {
        enabled = true

        # Additional data sources — Mimir, Loki, Tempo
        additionalDataSources = [
          {
            name      = "Mimir"
            type      = "prometheus"
            url       = "http://mimir-query-frontend.${var.monitoring_namespace}.svc.cluster.local:8080/prometheus"
            access    = "proxy"
            isDefault = true
          },
          {
            name   = "Loki"
            type   = "loki"
            url    = "http://loki-read.${var.monitoring_namespace}.svc.cluster.local:3100"
            access = "proxy"
          },
          {
            name   = "Tempo"
            type   = "tempo"
            url    = "http://tempo-query-frontend.${var.monitoring_namespace}.svc.cluster.local:3100"
            access = "proxy"
          }
        ]

        # Service type — ClusterIP for internal access
        service = {
          type = "ClusterIP"
        }

        # Environment label
        env = {
          GF_SERVER_ROOT_URL = "http://localhost:3000"
        }
      }

      # AlertManager — deployed but routing configured in Story 7.1 (AC: #5 prep)
      alertmanager = {
        enabled = true
      }
    }

    # Global labels
    globalConfig = {
      cluster_name = "aks-${var.environment}"
    }
  })]

  depends_on = [
    kubernetes_namespace.monitoring,
    helm_release.mimir,
    helm_release.loki,
    helm_release.tempo,
  ]
}

# --------------------------------------------------------------------------
# OpenTelemetry Operator + Python Instrumentation CRs (Task 8: AC #7)
# Architecture Decision 5.1: Zero-code auto-instrumentation via pod annotations
# Traces sent to Tempo distributor on OTLP/HTTP port 4318
# --------------------------------------------------------------------------

resource "helm_release" "otel_operator" {
  name       = "opentelemetry-operator"
  repository = "https://open-telemetry.github.io/opentelemetry-helm-charts"
  chart      = "opentelemetry-operator"
  version    = var.otel_operator_chart_version
  namespace  = kubernetes_namespace.monitoring.metadata[0].name
  timeout    = var.otel_operator_helm_timeout
  wait       = true

  set {
    name  = "manager.collectorImage.repository"
    value = "otel/opentelemetry-collector-contrib"
  }

  depends_on = [
    kubernetes_namespace.monitoring,
    helm_release.tempo,
  ]
}

# --------------------------------------------------------------------------
# Python Instrumentation CR per business namespace (Task 8.2, 8.3)
# Creates an Instrumentation resource in each namespace so pods annotated
# with instrumentation.opentelemetry.io/inject-python: "true" get
# auto-instrumented with traces sent to Tempo distributor.
# --------------------------------------------------------------------------

resource "kubernetes_manifest" "otel_instrumentation" {
  for_each = toset(var.namespaces)

  manifest = {
    apiVersion = "opentelemetry.io/v1alpha1"
    kind       = "Instrumentation"

    metadata = {
      name      = "python-instrumentation"
      namespace = each.value
    }

    spec = {
      exporter = {
        endpoint = "http://tempo-distributor.${var.monitoring_namespace}.svc.cluster.local:4318"
      }

      propagators = ["tracecontext", "baggage"]

      python = {
        image = "ghcr.io/open-telemetry/opentelemetry-operator/autoinstrumentation-python:latest"
        env = [
          {
            name  = "OTEL_TRACES_EXPORTER"
            value = "otlp"
          },
          {
            name  = "OTEL_EXPORTER_OTLP_PROTOCOL"
            value = "http/protobuf"
          },
          {
            name  = "OTEL_RESOURCE_ATTRIBUTES"
            value = "service.namespace=${each.value},deployment.environment=${var.environment}"
          }
        ]
      }
    }
  }

  depends_on = [helm_release.otel_operator]
}

# --------------------------------------------------------------------------
# Monitoring Module Variables (Story 5.1)
# LGTM Observability Stack: Robusta, Mimir, Loki, Tempo, OTel Operator
# --------------------------------------------------------------------------

variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
  validation {
    condition     = contains(["dev", "prd"], var.environment)
    error_message = "Environment must be 'dev' or 'prd'."
  }
}

variable "location" {
  description = "Azure region for resource deployment"
  type        = string
}

variable "resource_group_name" {
  description = "Name of the resource group for monitoring resources"
  type        = string
}

# --------------------------------------------------------------------------
# Namespace Configuration
# --------------------------------------------------------------------------

variable "monitoring_namespace" {
  description = "Kubernetes namespace for LGTM stack deployment"
  type        = string
  default     = "monitoring"
}

variable "namespaces" {
  description = "List of business area namespace names for OTel Instrumentation CRs"
  type        = list(string)
  default     = ["logistica"]
}

# --------------------------------------------------------------------------
# AKS Integration
# --------------------------------------------------------------------------

variable "aks_oidc_issuer_url" {
  description = "OIDC Issuer URL from AKS cluster for Workload Identity federation"
  type        = string
}

variable "aks_subnet_id" {
  description = "Resource ID of the AKS user subnet for storage network ACLs"
  type        = string
  default     = ""
}

# --------------------------------------------------------------------------
# Robusta / kube-prometheus-stack Configuration (AC: #1, #5, #6)
# --------------------------------------------------------------------------

variable "robusta_chart_version" {
  description = "Robusta Helm chart version"
  type        = string
  default     = "0.10.31"
}

variable "robusta_helm_timeout" {
  description = "Timeout in seconds for the Robusta Helm release"
  type        = number
  default     = 900
  validation {
    condition     = var.robusta_helm_timeout >= 120 && var.robusta_helm_timeout <= 1800
    error_message = "Helm timeout must be between 120 and 1800 seconds."
  }
}

variable "prometheus_scrape_interval" {
  description = "Prometheus scrape interval for CronJob metrics (NFR26: <= 30s)"
  type        = string
  default     = "30s"
  validation {
    condition     = can(regex("^[0-9]+s$", var.prometheus_scrape_interval))
    error_message = "Scrape interval must be in seconds format (e.g., '30s')."
  }
}

# --------------------------------------------------------------------------
# Mimir Configuration (AC: #2)
# --------------------------------------------------------------------------

variable "mimir_chart_version" {
  description = "Grafana Mimir distributed Helm chart version"
  type        = string
  default     = "5.6.0"
}

variable "mimir_helm_timeout" {
  description = "Timeout in seconds for the Mimir Helm release"
  type        = number
  default     = 600
}

variable "mimir_retention_days" {
  description = "Mimir long-term metrics retention in days (architecture: 365)"
  type        = number
  default     = 365
  validation {
    condition     = var.mimir_retention_days >= 30
    error_message = "Mimir retention must be at least 30 days."
  }
}

# --------------------------------------------------------------------------
# Loki Configuration (AC: #3)
# --------------------------------------------------------------------------

variable "loki_chart_version" {
  description = "Grafana Loki Helm chart version"
  type        = string
  default     = "6.53.0"
}

variable "loki_helm_timeout" {
  description = "Timeout in seconds for the Loki Helm release"
  type        = number
  default     = 600
}

# --------------------------------------------------------------------------
# Tempo Configuration (AC: #4)
# --------------------------------------------------------------------------

variable "tempo_chart_version" {
  description = "Grafana Tempo distributed Helm chart version"
  type        = string
  default     = "1.48.1"
}

variable "tempo_helm_timeout" {
  description = "Timeout in seconds for the Tempo Helm release"
  type        = number
  default     = 600
}

# --------------------------------------------------------------------------
# OpenTelemetry Operator Configuration (AC: #7)
# --------------------------------------------------------------------------

variable "otel_operator_chart_version" {
  description = "OpenTelemetry Operator Helm chart version"
  type        = string
  default     = "0.78.0"
}

variable "otel_operator_helm_timeout" {
  description = "Timeout in seconds for the OTel Operator Helm release"
  type        = number
  default     = 300
}

# --------------------------------------------------------------------------
# Common
# --------------------------------------------------------------------------

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

